import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"ページ設定","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Page/page-settings.md","filePath":"ja-JP/Page/page-settings.md","lastUpdated":1781962217000}'),i={name:"ja-JP/Page/page-settings.md"};function s(l,t,o,n,h,p){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="ページ設定" tabindex="-1">ページ設定 <a class="header-anchor" href="#ページ設定" aria-label="Permalink to &quot;ページ設定&quot;">​</a></h1><p>ページ設定では、ImgBed の表示、公開ページ、アップロード体験に関わる基本項目を調整できます。</p><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; ページ設定</span></span></code></pre></div><h2 id="主な設定" tabindex="-1">主な設定 <a class="header-anchor" href="#主な設定" aria-label="Permalink to &quot;主な設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>サイト名</td><td>ブラウザタイトルやページ上の表示名に使います</td></tr><tr><td>サイト説明</td><td>サイトの説明文として表示します</td></tr><tr><td>ロゴ / アイコン</td><td>画面やブラウザで使う画像を設定します</td></tr><tr><td>背景画像</td><td>トップページの背景に使います</td></tr><tr><td>フッター情報</td><td>コピーライトや外部リンクなどを表示します</td></tr><tr><td>アップロード説明</td><td>利用者に見せるアップロード欄の補足文を設定します</td></tr></tbody></table><h2 id="公開ページまわり" tabindex="-1">公開ページまわり <a class="header-anchor" href="#公開ページまわり" aria-label="Permalink to &quot;公開ページまわり&quot;">​</a></h2><p>訪問者向けページを使う場合は、公開ディレクトリ、アクセスモード、画像読み込み方法と合わせて確認してください。</p><p>特に公開ギャラリーやランダム画像 API を使う場合、ページ設定だけでなく、その他設定側の公開範囲も一緒に見る必要があります。</p><h2 id="変更後の確認" tabindex="-1">変更後の確認 <a class="header-anchor" href="#変更後の確認" aria-label="Permalink to &quot;変更後の確認&quot;">​</a></h2><ol><li>設定を保存します。</li><li>トップページを再読み込みします。</li><li>PC とスマートフォン幅の両方で表示を確認します。</li><li>ロゴ、背景、説明文、フッターリンクが意図通り表示されるか確認します。</li></ol><p>画像が反映されない場合は、画像 URL が開けるか、キャッシュが残っていないかを確認してください。</p>',12)])])}const b=a(i,[["render",s]]);export{_ as __pageData,b as default};
